#include <stdio.h>
int main(){
    int T;
    if(scanf("%d", &T)!=1) return 0;
    while(T--){
        double a,b;
        if(scanf("%lf %lf", &a, &b)!=2) return 0;
        double prod = a*b;
        printf("Product: %.2f\n", prod);
    }
    return 0;
}

