int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T;
    if(!(cin>>T)) return 0;
    while(T--){
        double a,b;
        cin>>a>>b;
        double prod = a*b;
        // Use rounding that matches half-up behavior
        long long scaled = llround(prod * 100.0 + (prod >= 0 ? 1e-9 : -1e-9));
        double rounded = scaled / 100.0;
        cout<<"Product: "<<fixed<<setprecision(2)<<rounded<<"\n";
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;
import java.math.*;
public class Main{
    public static void main(String[] args) throws Exception{
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine();
        if(line==null || line.isEmpty()) return;
        int T = Integer.parseInt(line.trim());
        StringBuilder sb = new StringBuilder();
        for(int i=0;i<T;i++){
            StringTokenizer st = new StringTokenizer(br.readLine());
            BigDecimal a = new BigDecimal(st.nextToken());
            BigDecimal b = new BigDecimal(st.nextToken());
            BigDecimal prod = a.multiply(b);
            prod = prod.setScale(2, RoundingMode.HALF_UP);
            sb.append("Product: ").append(prod.toPlainString());
            if(i<T-1) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

