const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = parseInt(input[idx++], 10);
let out = [];
for(let i = 0; i < T; i++){
    const a = parseFloat(input[idx++]);
    const b = parseFloat(input[idx++]);
    const prod = a * b;
    // Apply half-up rounding to two decimal places
    const eps = prod >= 0 ? 1e-9 : -1e-9;
    const rounded = Math.round((prod + eps) * 100) / 100;
    out.push(`Product: ${rounded.toFixed(2)}`);
}
console.log(out.join('\n'));
